import{_ as d,C as c,o as a,c as p,a2 as o,b as i,w as e,a as s,E as n,a3 as l}from"./chunks/framework.B72_uj9U.js";const k=JSON.parse('{"title":"Warp Tool System","description":"","frontmatter":{"title":"Warp Tool System","status":"complete"},"headers":[],"relativePath":"research/agents/warp/tool-system.md","filePath":"research/agents/warp/tool-system.md"}'),u={name:"research/agents/warp/tool-system.md"};function h(g,t,m,b,f,A){const r=c("Mermaid");return a(),p("div",null,[t[6]||(t[6]=o('<h1 id="tool-system" tabindex="-1">Tool System <a class="header-anchor" href="#tool-system" aria-label="Permalink to &quot;Tool System&quot;">​</a></h1><blockquote><p>Warp&#39;s tool system spans from basic file operations to Computer Use (desktop interaction via screenshots), with MCP integration for extensibility, a built-in code editor with LSP support, interactive code review, and voice input.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Warp&#39;s agent has access to a broad set of tools that fall into several categories:</p><ol><li><strong>Core tools</strong>: File operations, shell commands, web search</li><li><strong>Terminal-native tools</strong>: PTY interaction, block reading, interactive process control</li><li><strong>Editor tools</strong>: Built-in code editor with LSP, interactive code review</li><li><strong>Extended tools</strong>: MCP integrations, Computer Use, voice input</li><li><strong>Workflow tools</strong>: Task lists, planning, Warp Drive storage</li><li><strong>Proactive tools</strong>: Active AI error detection and fix suggestions</li></ol><h2 id="core-tools" tabindex="-1">Core Tools <a class="header-anchor" href="#core-tools" aria-label="Permalink to &quot;Core Tools&quot;">​</a></h2><h3 id="file-operations" tabindex="-1">File Operations <a class="header-anchor" href="#file-operations" aria-label="Permalink to &quot;File Operations&quot;">​</a></h3><p>The agent can perform standard file operations:</p><table tabindex="0"><thead><tr><th>Operation</th><th>Description</th><th>Permission Required</th></tr></thead><tbody><tr><td>Read file</td><td>Read contents of a file</td><td>No (read-only)</td></tr><tr><td>Write file</td><td>Create or overwrite a file</td><td>Yes (write)</td></tr><tr><td>Edit file</td><td>Modify specific portions of a file</td><td>Yes (write)</td></tr><tr><td>Delete file</td><td>Remove a file</td><td>Yes (write)</td></tr><tr><td>Move/rename</td><td>Move or rename files</td><td>Yes (write)</td></tr><tr><td>List directory</td><td>List directory contents</td><td>No (read-only)</td></tr><tr><td>Search files</td><td>Search file names with patterns</td><td>No (read-only)</td></tr><tr><td>Search content</td><td>Grep/ripgrep through file contents</td><td>No (read-only)</td></tr></tbody></table><p>File operations are performed directly by the agent (not by generating shell commands), which provides:</p><ul><li>Better error handling and reporting</li><li>Atomic operations (write succeeds or fails completely)</li><li>Structured diffs for review</li><li>Integration with the interactive code review system</li></ul><h3 id="shell-command-execution" tabindex="-1">Shell Command Execution <a class="header-anchor" href="#shell-command-execution" aria-label="Permalink to &quot;Shell Command Execution&quot;">​</a></h3>',12)),(a(),i(l,null,{default:e(()=>[n(r,{id:"mermaid-188",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20Agent%20as%20Agent%20Action%0A%20%20%20%20participant%20Term%20as%20Terminal%0A%20%20%20%20Agent-%3E%3ETerm%3A%20Write%20command%20to%20PTY%0A%20%20%20%20Note%20over%20Term%3A%20New%20Block%20created%2C%20command%20executes%0A%20%20%20%20Term--%3E%3EAgent%3A%20Read%20block%20output%20(output%20captured%2C%20exit%20code%20recorded)%0A%20%20%20%20Note%20over%20Agent%3A%20Evaluate%20result%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[7]||(t[7]=o(`<p>Shell execution in Warp differs from wrapper agents:</p><ul><li>Commands create <strong>blocks</strong> with structured metadata (exit code, duration, CWD)</li><li>Agent reads output from the block&#39;s grid, not from stdout capture</li><li>Long-running commands can be monitored asynchronously</li><li>Interactive commands trigger Full Terminal Use mode</li></ul><h3 id="web-search" tabindex="-1">Web Search <a class="header-anchor" href="#web-search" aria-label="Permalink to &quot;Web Search&quot;">​</a></h3><p>The agent can search the web for information:</p><ul><li>Query web search engines</li><li>Retrieve and parse web page content</li><li>Extract relevant information for the current task</li><li>Useful for looking up API docs, error messages, library usage</li></ul><h2 id="terminal-native-tools" tabindex="-1">Terminal-Native Tools <a class="header-anchor" href="#terminal-native-tools" aria-label="Permalink to &quot;Terminal-Native Tools&quot;">​</a></h2><p>These tools are unique to Warp&#39;s terminal-native architecture:</p><h3 id="block-reading" tabindex="-1">Block Reading <a class="header-anchor" href="#block-reading" aria-label="Permalink to &quot;Block Reading&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Agent can:</span></span>
<span class="line"><span>├── Read output of any visible block</span></span>
<span class="line"><span>├── Read output of specific block by reference</span></span>
<span class="line"><span>├── Search across block outputs</span></span>
<span class="line"><span>├── Read metadata (exit code, duration, CWD)</span></span>
<span class="line"><span>└── Reference blocks in conversation context</span></span></code></pre></div><h3 id="pty-interaction-full-terminal-use" tabindex="-1">PTY Interaction (Full Terminal Use) <a class="header-anchor" href="#pty-interaction-full-terminal-use" aria-label="Permalink to &quot;PTY Interaction (Full Terminal Use)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Description</th></tr></thead><tbody><tr><td>Write to PTY</td><td>Send keystrokes/text to running process</td></tr><tr><td>Read buffer</td><td>Read current terminal buffer content</td></tr><tr><td>Send control sequences</td><td>Ctrl+C, Ctrl+D, Ctrl+Z, etc.</td></tr><tr><td>Detect prompt</td><td>Identify when process is waiting for input</td></tr><tr><td>Monitor output</td><td>Watch for specific patterns in output stream</td></tr><tr><td>Attach to process</td><td>Connect to already-running interactive process</td></tr></tbody></table><h3 id="interactive-process-control" tabindex="-1">Interactive Process Control <a class="header-anchor" href="#interactive-process-control" aria-label="Permalink to &quot;Interactive Process Control&quot;">​</a></h3><p>The agent can manage interactive processes:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Supported Interactive Tools:</span></span>
<span class="line"><span>├── Databases:     psql, mysql, sqlite3, redis-cli, mongosh</span></span>
<span class="line"><span>├── REPLs:         python, node, irb, ghci, erl</span></span>
<span class="line"><span>├── Editors:       vim, nano (limited), emacs</span></span>
<span class="line"><span>├── Debuggers:     gdb, lldb, pdb, node --inspect</span></span>
<span class="line"><span>├── Dev servers:   npm run dev, flask run, cargo watch</span></span>
<span class="line"><span>├── Containers:    docker exec, kubectl exec</span></span>
<span class="line"><span>├── Package mgrs:  npm init (interactive prompts)</span></span>
<span class="line"><span>└── Other:         ssh sessions, tmux, screen</span></span></code></pre></div><h2 id="editor-tools" tabindex="-1">Editor Tools <a class="header-anchor" href="#editor-tools" aria-label="Permalink to &quot;Editor Tools&quot;">​</a></h2><h3 id="built-in-code-editor-with-lsp" tabindex="-1">Built-in Code Editor with LSP <a class="header-anchor" href="#built-in-code-editor-with-lsp" aria-label="Permalink to &quot;Built-in Code Editor with LSP&quot;">​</a></h3><p>Warp includes a code editor that goes beyond terminal text editing:</p><ul><li><strong>Syntax highlighting</strong>: Language-aware highlighting for displayed code</li><li><strong>LSP integration</strong>: Language Server Protocol support for: <ul><li>Go-to-definition</li><li>Find references</li><li>Hover information</li><li>Completions</li><li>Diagnostics (errors, warnings)</li></ul></li><li><strong>Inline editing</strong>: Edit files within the terminal without launching external editors</li><li><strong>Diff view</strong>: Side-by-side or inline diff display for changes</li></ul><p>The LSP integration means the agent has access to semantic code information, not just text pattern matching. It can:</p><ul><li>Navigate to symbol definitions</li><li>Find all usages of a function</li><li>Understand type information</li><li>Detect errors before running code</li></ul><h3 id="interactive-code-review" tabindex="-1">Interactive Code Review <a class="header-anchor" href="#interactive-code-review" aria-label="Permalink to &quot;Interactive Code Review&quot;">​</a></h3><p>When the agent makes code changes, they go through an interactive review process:</p>`,22)),(a(),i(l,null,{default:e(()=>[n(r,{id:"mermaid-413",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20ICR%5B%22Interactive%20Code%20Review%22%5D%0A%20%20%20%20%20%20%20%20F%5B%22File%3A%20src%2Fauth%2Flogin.ts%22%5D%0A%20%20%20%20%20%20%20%20D%5B%22-%20const%20token%20%3D%20jwt.sign(payload%2C%20secret)%3B%3Cbr%2F%3E%2B%20const%20session%20%3D%20await%20createSession(user.id)%3B%3Cbr%2F%3E%2B%20res.cookie('session_id'%2C%20session.id%2C%20%7B%3Cbr%2F%3E%2B%20%20%20httpOnly%3A%20true%2C%20secure%3A%20true%2C%3Cbr%2F%3E%2B%20%7D)%3B%22%5D%0A%20%20%20%20%20%20%20%20CM%5B%22%F0%9F%92%AC%20Comment%3A%20Should%20we%20also%20set%20SameSite%20attribute%3F%22%5D%0A%20%20%20%20%20%20%20%20AC%5B%22%5BAccept%5D%20%5BReject%5D%20%5BEdit%5D%20%5BComment%5D%22%5D%0A%20%20%20%20%20%20%20%20F%20--%3E%20D%20--%3E%20CM%20--%3E%20AC%0A%20%20%20%20end%0A"})]),fallback:e(()=>[...t[1]||(t[1]=[s(" Loading... ",-1)])]),_:1})),t[8]||(t[8]=o('<p>Features of interactive code review:</p><ul><li><strong>Per-file diff view</strong>: Each changed file shown separately</li><li><strong>Inline comments</strong>: User can add comments on specific lines</li><li><strong>Accept/reject per hunk</strong>: Granular control over which changes to apply</li><li><strong>Agent response to comments</strong>: Agent can revise changes based on review feedback</li><li><strong>Batch operations</strong>: Accept all, reject all</li><li><strong>Undo</strong>: Revert applied changes</li></ul><h2 id="mcp-model-context-protocol-integration" tabindex="-1">MCP (Model Context Protocol) Integration <a class="header-anchor" href="#mcp-model-context-protocol-integration" aria-label="Permalink to &quot;MCP (Model Context Protocol) Integration&quot;">​</a></h2><p>Warp supports the <strong>Model Context Protocol</strong> for extensible tool integration:</p><h3 id="what-mcp-enables" tabindex="-1">What MCP Enables <a class="header-anchor" href="#what-mcp-enables" aria-label="Permalink to &quot;What MCP Enables&quot;">​</a></h3>',5)),(a(),i(l,null,{default:e(()=>[n(r,{id:"mermaid-458",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20subgraph%20WA%5B%22Warp%20Agent%22%5D%0A%20%20%20%20%20%20%20%20BT%5B%22Built-in%20Tools%3Cbr%2F%3EFiles%20%2F%20Shell%20%2F%20Web%20%2F%20Editor%20%2F%20...%22%5D%0A%20%20%20%20%20%20%20%20MT%5B%22MCP-Connected%20Tools%3Cbr%2F%3EDatabases%20%2F%20APIs%20(Jira%2C%20Linear)%3Cbr%2F%3ECloud%20services%20%2F%20Custom%20tools%3Cbr%2F%3EKnowledge%20bases%20%2F%20Monitoring%20systems%22%5D%0A%20%20%20%20end%0A"})]),fallback:e(()=>[...t[2]||(t[2]=[s(" Loading... ",-1)])]),_:1})),t[9]||(t[9]=o('<h3 id="mcp-configuration" tabindex="-1">MCP Configuration <a class="header-anchor" href="#mcp-configuration" aria-label="Permalink to &quot;MCP Configuration&quot;">​</a></h3><p>MCP servers are configured in Warp&#39;s settings:</p><ul><li><strong>Per-project</strong>: MCP servers can be scoped to specific projects</li><li><strong>Global</strong>: MCP servers available across all projects</li><li><strong>Discovery</strong>: Warp can discover MCP servers from project configuration</li><li><strong>Authentication</strong>: Support for OAuth, API keys, and other auth mechanisms</li></ul><h3 id="mcp-tool-types" tabindex="-1">MCP Tool Types <a class="header-anchor" href="#mcp-tool-types" aria-label="Permalink to &quot;MCP Tool Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Resources</strong></td><td>Read-only data sources</td><td>Database schemas, API docs</td></tr><tr><td><strong>Tools</strong></td><td>Executable actions</td><td>Create Jira ticket, deploy service</td></tr><tr><td><strong>Prompts</strong></td><td>Reusable prompt templates</td><td>Code review checklist</td></tr></tbody></table><h2 id="computer-use" tabindex="-1">Computer Use <a class="header-anchor" href="#computer-use" aria-label="Permalink to &quot;Computer Use&quot;">​</a></h2><p>Warp&#39;s agent can interact with the desktop environment beyond the terminal:</p><h3 id="how-computer-use-works" tabindex="-1">How Computer Use Works <a class="header-anchor" href="#how-computer-use-works" aria-label="Permalink to &quot;How Computer Use Works&quot;">​</a></h3>',8)),(a(),i(l,null,{default:e(()=>[n(r,{id:"mermaid-549",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20Agent%20as%20Agent%20Action%0A%20%20%20%20participant%20Desktop%20as%20Desktop%0A%20%20%20%20Agent-%3E%3EDesktop%3A%20Take%20screenshot%0A%20%20%20%20Desktop--%3E%3EAgent%3A%20Image%20data%20(capture%20screen%20content)%0A%20%20%20%20Note%20over%20Agent%3A%20Analyze%20image%20(LLM%20vision%20processing)%0A%20%20%20%20Agent-%3E%3EDesktop%3A%20Click%20at%20(x%2Cy)%20%E2%80%94%20mouse%20click%0A%20%20%20%20Agent-%3E%3EDesktop%3A%20Type%20text%20%E2%80%94%20keyboard%20input%0A%20%20%20%20Agent-%3E%3EDesktop%3A%20Move%20mouse%20%E2%80%94%20mouse%20movement%0A%20%20%20%20Agent-%3E%3EDesktop%3A%20Take%20screenshot%0A%20%20%20%20Desktop--%3E%3EAgent%3A%20Image%20data%20(verify%20result)%0A"})]),fallback:e(()=>[...t[3]||(t[3]=[s(" Loading... ",-1)])]),_:1})),t[10]||(t[10]=o('<h3 id="computer-use-capabilities" tabindex="-1">Computer Use Capabilities <a class="header-anchor" href="#computer-use-capabilities" aria-label="Permalink to &quot;Computer Use Capabilities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Description</th></tr></thead><tbody><tr><td><strong>Screenshot</strong></td><td>Capture current screen content</td></tr><tr><td><strong>Click</strong></td><td>Click at specific screen coordinates</td></tr><tr><td><strong>Type</strong></td><td>Type text via keyboard simulation</td></tr><tr><td><strong>Scroll</strong></td><td>Scroll in applications</td></tr><tr><td><strong>Drag</strong></td><td>Drag-and-drop operations</td></tr><tr><td><strong>Wait</strong></td><td>Wait for UI elements to appear</td></tr></tbody></table><h3 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h3><ul><li>Interacting with GUI applications that don&#39;t have CLI interfaces</li><li>Browser automation for web-based tasks</li><li>GUI testing and verification</li><li>Filling out forms in desktop applications</li><li>Taking screenshots for documentation</li></ul><blockquote><p><strong>Note</strong>: Computer Use requires explicit permission and is governed by the same permission model as other agent actions.</p></blockquote><h2 id="task-lists" tabindex="-1">Task Lists <a class="header-anchor" href="#task-lists" aria-label="Permalink to &quot;Task Lists&quot;">​</a></h2><p>Warp provides structured task tracking for complex multi-step workflows:</p><h3 id="task-list-features" tabindex="-1">Task List Features <a class="header-anchor" href="#task-list-features" aria-label="Permalink to &quot;Task List Features&quot;">​</a></h3>',8)),(a(),i(l,null,{default:e(()=>[n(r,{id:"mermaid-659",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20TL%5B%22Task%20List%3A%20Deploy%20v2.0%22%5D%0A%20%20%20%20%20%20%20%20T1%5B%22%E2%9C%85%20Update%20version%20in%20package.json%22%5D%0A%20%20%20%20%20%20%20%20T2%5B%22%E2%9C%85%20Run%20full%20test%20suite%22%5D%0A%20%20%20%20%20%20%20%20T3%5B%22%E2%98%90%20Build%20production%20bundle%22%5D%0A%20%20%20%20%20%20%20%20T4%5B%22%E2%98%90%20Deploy%20to%20staging%22%5D%0A%20%20%20%20%20%20%20%20T5%5B%22%E2%98%90%20Run%20smoke%20tests%22%5D%0A%20%20%20%20%20%20%20%20T6%5B%22%E2%98%90%20Deploy%20to%20production%22%5D%0A%20%20%20%20%20%20%20%20T7%5B%22%E2%98%90%20Verify%20health%20checks%22%5D%0A%20%20%20%20%20%20%20%20P%5B%22Progress%3A%202%2F7%20(28%25)%20%E2%80%94%20%5BContinue%5D%20%5BEdit%5D%20%5BShare%5D%22%5D%0A%20%20%20%20%20%20%20%20T1%20--%3E%20T2%20--%3E%20T3%20--%3E%20T4%20--%3E%20T5%20--%3E%20T6%20--%3E%20T7%20--%3E%20P%0A%20%20%20%20end%0A"})]),fallback:e(()=>[...t[4]||(t[4]=[s(" Loading... ",-1)])]),_:1})),t[11]||(t[11]=o('<ul><li><strong>Agent-generated</strong>: Agent creates task lists from complex requests</li><li><strong>User-editable</strong>: User can add, remove, or reorder tasks</li><li><strong>Trackable</strong>: Progress visible as agent works through tasks</li><li><strong>Resumable</strong>: Task lists persist across sessions</li><li><strong>Shareable</strong>: Share task lists with team via Warp Drive</li></ul><h2 id="voice-input" tabindex="-1">Voice Input <a class="header-anchor" href="#voice-input" aria-label="Permalink to &quot;Voice Input&quot;">​</a></h2><p>Warp supports voice as an input modality:</p><ul><li><strong>Speech-to-text</strong>: Voice input transcribed to text commands/requests</li><li><strong>Natural language</strong>: Speak requests in natural language, agent interprets</li><li><strong>Hands-free</strong>: Useful when debugging physical hardware, pair programming</li><li><strong>Context-aware</strong>: Voice input has same context as typed input (blocks, files, etc.)</li></ul><h2 id="active-ai" tabindex="-1">Active AI <a class="header-anchor" href="#active-ai" aria-label="Permalink to &quot;Active AI&quot;">​</a></h2><p>Active AI is Warp&#39;s proactive assistance system:</p><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3>',7)),(a(),i(l,null,{default:e(()=>[n(r,{id:"mermaid-724",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20F%5B%22Command%20fails%20(non-zero%20exit%20code)%22%5D%20--%3E%20AD%5B%22Active%20AI%20Detection%3Cbr%2F%3EAnalyze%3A%3Cbr%2F%3E-%20Error%20output%20text%3Cbr%2F%3E-%20Exit%20code%3Cbr%2F%3E-%20Command%20context%3Cbr%2F%3E-%20Previous%20related%20commands%3Cbr%2F%3E-%20Known%20error%20patterns%22%5D%0A%20%20%20%20AD%20--%3E%20FR%5B%22Fix%20Recommendation%3Cbr%2F%3Ee.g.%20'npm%20test%20failed%20because%20module%20lodash%20not%20found.%3Cbr%2F%3ERun%3A%20npm%20install%20lodash'%3Cbr%2F%3E%5BApply%20Fix%5D%20%5BDismiss%5D%20%5BExplain%5D%22%5D%0A"})]),fallback:e(()=>[...t[5]||(t[5]=[s(" Loading... ",-1)])]),_:1})),t[12]||(t[12]=o('<h3 id="active-ai-features" tabindex="-1">Active AI Features <a class="header-anchor" href="#active-ai-features" aria-label="Permalink to &quot;Active AI Features&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Error detection</strong></td><td>Monitors command exit codes and output for errors</td></tr><tr><td><strong>Pattern matching</strong></td><td>Recognizes common error patterns across languages</td></tr><tr><td><strong>Fix suggestion</strong></td><td>Proposes specific commands or code changes to fix errors</td></tr><tr><td><strong>One-click apply</strong></td><td>User can apply suggested fix with a single click</td></tr><tr><td><strong>Learning</strong></td><td>Suggestions improve based on project context and history</td></tr><tr><td><strong>Non-intrusive</strong></td><td>Appears as subtle suggestion, doesn&#39;t interrupt workflow</td></tr></tbody></table><h2 id="tool-invocation-priority" tabindex="-1">Tool Invocation Priority <a class="header-anchor" href="#tool-invocation-priority" aria-label="Permalink to &quot;Tool Invocation Priority&quot;">​</a></h2><p>When the agent needs to accomplish a task, it selects tools in this general priority:</p><ol><li><strong>Built-in file operations</strong> — for direct file manipulation</li><li><strong>Shell commands</strong> — for system operations, builds, tests</li><li><strong>LSP queries</strong> — for code navigation and understanding</li><li><strong>Web search</strong> — for external information</li><li><strong>MCP tools</strong> — for integrated service operations</li><li><strong>Computer Use</strong> — for GUI interactions (last resort)</li></ol><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Warp&#39;s tool system is the most comprehensive of any terminal-based agent, combining traditional coding tools (files, shell, search) with terminal-native capabilities (PTY interaction, block reading) and advanced features (Computer Use, LSP, MCP, interactive code review). The breadth of tools reflects Warp&#39;s position as a full terminal replacement rather than a single-purpose coding agent.</p>',7))])}const C=d(u,[["render",h]]);export{k as __pageData,C as default};
